import java.util.*;

public class Main {

    /**
     * Edge 表示图中的一条边
     *
     * 例如：
     * 如果有关系：a 在 b 的右边
     * 那么从 b 可以走到 a，移动方向是：
     * dx = 1, dy = 0
     *
     * to：当前拼图块相邻的拼图块编号
     * dx：列方向偏移量，向右为 +1，向左为 -1
     * dy：行方向偏移量，向下为 +1，向上为 -1
     */
    static class Edge {
        int to;
        int dx;
        int dy;

        Edge(int to, int dx, int dy) {
            this.to = to;
            this.dx = dx;
            this.dy = dy;
        }
    }

    /**
     * Point 表示某个拼图块的坐标
     *
     * 注意：
     * x 表示列坐标，向右增加
     * y 表示行坐标，向下增加
     *
     * 所以最后放入二维数组时：
     * row = y
     * col = x
     */
    static class Point {
        int x;
        int y;

        Point(int x, int y) {
            this.x = x;
            this.y = y;
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);

        // m 行，n 列
        int m = sc.nextInt();
        int n = sc.nextInt();

        // 拼图总数
        int total = m * n;

        // 相对位置关系数量
        int k = sc.nextInt();

        /**
         * graph[i] 存储与第 i 块拼图相邻的拼图块
         *
         * 因为拼图块编号是 1 到 total，
         * 所以数组大小开 total + 1，方便直接用编号作为下标。
         */
        List<Edge>[] graph = new ArrayList[total + 1];

        // 初始化每个点的邻接表
        for (int i = 1; i <= total; i++) {
            graph[i] = new ArrayList<>();
        }

        /**
         * 读取 k 条相对位置关系
         *
         * 输入格式：
         * a b dir
         *
         * 含义：
         * a 在 b 的 dir 方向
         *
         * 例如：
         * 4 3 U
         * 表示 4 在 3 的上方
         */
        for (int i = 0; i < k; i++) {
            int a = sc.nextInt();
            int b = sc.nextInt();
            String dir = sc.next();

            /**
             * dx、dy 表示：
             * 从 b 走到 a 时，坐标应该怎么变化
             *
             * 坐标规则：
             * x 表示列，向右增加
             * y 表示行，向下增加
             */
            int dx = 0, dy = 0;

            if (dir.equals("U")) {
                // a 在 b 上方
                // 从 b 到 a：行数减少 1
                dx = 0;
                dy = -1;
            } else if (dir.equals("B")) {
                // a 在 b 下方
                // 从 b 到 a：行数增加 1
                dx = 0;
                dy = 1;
            } else if (dir.equals("L")) {
                // a 在 b 左方
                // 从 b 到 a：列数减少 1
                dx = -1;
                dy = 0;
            } else if (dir.equals("R")) {
                // a 在 b 右方
                // 从 b 到 a：列数增加 1
                dx = 1;
                dy = 0;
            }

            /**
             * 建图：
             *
             * 已知 a 在 b 的 dir 方向，
             * 所以从 b 可以走到 a，偏移量是 dx、dy。
             */
            graph[b].add(new Edge(a, dx, dy));

            /**
             * 同时还要加入反向边。
             *
             * 如果从 b 到 a 的偏移是 dx、dy，
             * 那么从 a 到 b 的偏移就是 -dx、-dy。
             *
             * 这样 BFS 时无论从哪个拼图块开始，
             * 都可以沿着关系推导出其它拼图块的位置。
             */
            graph[a].add(new Edge(b, -dx, -dy));
        }

        /**
         * pos[i] 表示第 i 块拼图的坐标
         *
         * 因为一开始我们不知道真实绝对坐标，
         * 所以先假设某一块拼图的位置是 (0, 0)，
         * 然后通过相对关系推出其它拼图块的相对坐标。
         */
        Point[] pos = new Point[total + 1];

        // visited[i] 表示第 i 块拼图是否已经计算过坐标
        boolean[] visited = new boolean[total + 1];

        Queue<Integer> queue = new LinkedList<>();

        /**
         * 从 1 号拼图块开始 BFS。
         *
         * 题目保证所有拼图能组成一个完整矩形，
         * 并且关系足够还原所有位置，
         * 所以从任意一块开始都可以。
         *
         * 这里把 1 号块的坐标暂时设为 (0, 0)。
         */
        visited[1] = true;
        pos[1] = new Point(0, 0);
        queue.offer(1);

        /**
         * BFS 推导所有拼图块的相对坐标
         */
        while (!queue.isEmpty()) {
            int cur = queue.poll();

            // 遍历当前拼图块的所有相邻拼图块
            for (Edge edge : graph[cur]) {
                int next = edge.to;

                // 如果 next 还没有计算过坐标，就根据 cur 的坐标推导出来
                if (!visited[next]) {
                    visited[next] = true;

                    /**
                     * next 的坐标 =
                     * 当前块 cur 的坐标 + 从 cur 到 next 的偏移量
                     */
                    pos[next] = new Point(
                            pos[cur].x + edge.dx,
                            pos[cur].y + edge.dy
                    );

                    queue.offer(next);
                }
            }
        }

        /**
         * BFS 得到的坐标可能包含负数。
         *
         * 例如：
         * 如果 1 号块在中间，
         * 它左边和上边的拼图块坐标就可能是负数。
         *
         * 但是二维数组下标不能是负数，
         * 所以要找到最小的 x 和 y，
         * 然后把所有坐标整体平移成非负数。
         */
        int minX = Integer.MAX_VALUE;
        int minY = Integer.MAX_VALUE;

        for (int i = 1; i <= total; i++) {
            minX = Math.min(minX, pos[i].x);
            minY = Math.min(minY, pos[i].y);
        }

        /**
         * ans[row][col] 表示最终拼图矩阵
         *
         * m 行 n 列：
         * row 范围是 0 到 m - 1
         * col 范围是 0 到 n - 1
         */
        int[][] ans = new int[m][n];

        /**
         * 将每个拼图块放入最终矩阵中
         */
        for (int i = 1; i <= total; i++) {
            // x 是列坐标，所以对应 col
            int col = pos[i].x - minX;

            // y 是行坐标，所以对应 row
            int row = pos[i].y - minY;

            ans[row][col] = i;
        }

        /**
         * 按从上到下、从左到右输出完整拼图矩阵
         */
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (j > 0) {
                    System.out.print(" ");
                }
                System.out.print(ans[i][j]);
            }
            System.out.println();
        }
    }
}

